import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"เพิ่ม Yandex Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/yandex.md","filePath":"th-TH/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"th-TH/upload/yandex.md"};function p(c,e,h,u,m,x){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="เพิ่ม-yandex-channel" tabindex="-1">เพิ่ม Yandex Channel <a class="header-anchor" href="#เพิ่ม-yandex-channel" aria-label="Permalink to &quot;เพิ่ม Yandex Channel&quot;">​</a></h1><h2 id="สิ่งที่ต้องเตรียมก่อน" tabindex="-1">สิ่งที่ต้องเตรียมก่อน <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อน" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อน&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>ทำไมต้องใช้</th></tr></thead><tbody><tr><td>Yandex account</td><td>ใช้ sign in และ authorize Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>ใช้ generate <code>Client ID</code> และ <code>Client Secret</code></td></tr><tr><td>ImgBed domain ของคุณ</td><td>ใช้เป็น OAuth redirect URI</td></tr><tr><td>Available Yandex Disk storage</td><td>ใช้เป็นพื้นที่เก็บ file จริง</td></tr></tbody></table><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><h3 id="step-1-สร้าง-yandex-oauth-app" tabindex="-1">Step 1: สร้าง Yandex OAuth App <a class="header-anchor" href="#step-1-สร้าง-yandex-oauth-app" aria-label="Permalink to &quot;Step 1: สร้าง Yandex OAuth App&quot;">​</a></h3><ol><li>เปิดหน้า create Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>ถ้าถูก redirect ไปหน้า sign in ให้ sign in ด้วย Yandex account ก่อน</li><li>สร้าง app ใหม่</li><li>ตั้งชื่อ app ให้จำง่าย เช่น <code>imgbed-yandex</code></li><li>หา callback หรือ redirect URL settings</li><li>ใส่:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-confirm-permissions" tabindex="-1">Step 2: Confirm Permissions <a class="header-anchor" href="#step-2-confirm-permissions" aria-label="Permalink to &quot;Step 2: Confirm Permissions&quot;">​</a></h3><p>สำหรับ ImgBed Yandex integration ปัจจุบัน ให้คง permissions สี่ตัวนี้ไว้ใน <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ให้ ImgBed store files ใน app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>อ่าน files และ download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Upload files, create folders และ delete files</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>อ่าน disk quota และ used space</td></tr></tbody></table><p>ถ้าเห็น permissions เหล่านี้ใน <code>Yandex ID API</code> จะเป็น optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Core upload, download, deletion และ quota features พึ่งพา permissions สี่ตัวใน <code>Yandex.Disk REST API</code> เป็นหลัก</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-copy-app-credentials" tabindex="-1">Step 3: Copy App Credentials <a class="header-anchor" href="#step-3-copy-app-credentials" aria-label="Permalink to &quot;Step 3: Copy App Credentials&quot;">​</a></h3><p>หลังสร้าง app แล้ว copy:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-ใส่-yandex-channel" tabindex="-1">Step 4: ใส่ Yandex Channel <a class="header-anchor" href="#step-4-ใส่-yandex-channel" aria-label="Permalink to &quot;Step 4: ใส่ Yandex Channel&quot;">​</a></h3><p>ใน Upload Settings เลือก <code>Yandex</code> แล้วกรอก:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>ใส่อะไร</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่าย เช่น <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>เว้นว่างไว้ก่อน</td></tr><tr><td>Root directory</td><td>Optional ค่าเริ่มต้นคือ <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-รับ-refresh-token" tabindex="-1">Step 5: รับ Refresh Token <a class="header-anchor" href="#step-5-รับ-refresh-token" aria-label="Permalink to &quot;Step 5: รับ Refresh Token&quot;">​</a></h3><ol><li>ใน ImgBed คลิก <code>Get Token</code></li><li>Sign in เข้า Yandex account ที่ต้องการเชื่อมต่อ</li><li>Approve authorization prompt</li><li>Callback page จะแสดง <code>Refresh Token</code></li><li>Copy token นั้น</li><li>กลับไปที่ ImgBed แล้ว paste ใน field <code>Refresh Token</code></li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h3><p>เมื่อกรอกครบทุก field แล้วให้ save channel</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เปิด Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; สร้าง app</span></span>
<span class="line"><span>-&gt; เพิ่ม https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Confirm Yandex Disk permissions</span></span>
<span class="line"><span>-&gt; Copy Client ID และ Client Secret</span></span>
<span class="line"><span>-&gt; ใส่ Client ID / Client Secret ใน ImgBed</span></span>
<span class="line"><span>-&gt; คลิก Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token จาก callback page</span></span>
<span class="line"><span>-&gt; Paste กลับเข้า ImgBed แล้ว save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const f=o(r,[["render",p]]);export{k as __pageData,f as default};
